import statistics

def avg_abs_dev(nums):
    if not nums: return 0.0
    mean_val = statistics.mean(nums)
    return statistics.mean(abs(x - mean_val) for x in nums)

if __name__ == "__main__":
    print(f"AAD: {avg_abs_dev([4, 1, 3, 2])}")
